import{_ as e,a,b as d,c as o,d as p,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const A=JSON.parse('{"title":"新增 Dropbox 渠道","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/dropbox.md","filePath":"zh-TW/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"zh-TW/upload/dropbox.md"};function h(b,t,x,m,u,g){return n(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="新增-dropbox-渠道" tabindex="-1">新增 Dropbox 渠道 <a class="header-anchor" href="#新增-dropbox-渠道" aria-label="Permalink to &quot;新增 Dropbox 渠道&quot;">​</a></h1><h2 id="新增前要準備什麼" tabindex="-1">新增前要準備什麼 <a class="header-anchor" href="#新增前要準備什麼" aria-label="Permalink to &quot;新增前要準備什麼&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要準備</th><th>用途</th></tr></thead><tbody><tr><td>Dropbox 帳號</td><td>登入 Dropbox 並授權應用程式</td></tr><tr><td>Dropbox App</td><td>取得 <code>App Key</code> 和 <code>App Secret</code></td></tr><tr><td>目前 ImgBed 網域</td><td>設定 OAuth 回呼網址</td></tr><tr><td>可用的 Dropbox 空間</td><td>實際存放圖片</td></tr></tbody></table><h2 id="新增步驟" tabindex="-1">新增步驟 <a class="header-anchor" href="#新增步驟" aria-label="Permalink to &quot;新增步驟&quot;">​</a></h2><h3 id="第一步-建立-dropbox-app" tabindex="-1">第一步：建立 Dropbox App <a class="header-anchor" href="#第一步-建立-dropbox-app" aria-label="Permalink to &quot;第一步：建立 Dropbox App&quot;">​</a></h3><ol><li>打開 Dropbox App Console：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>建立新的 App。</li><li>存取類型建議選：</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>替 App 取一個好辨識的名稱，例如 <code>imgbed-app</code>。</li><li>建立完成後進入 App 詳情頁。</li></ol><table tabindex="0"><thead><tr><th>存取類型</th><th>建議</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>推薦，權限範圍剛好符合 ImgBed 使用情境</td></tr><tr><td><code>Full Dropbox</code></td><td>不建議，權限太大，目前沒有必要</td></tr></tbody></table><p><img src="'+e+'" alt="建立 Dropbox App" loading="lazy"></p><h3 id="第二步-設定回呼網址" tabindex="-1">第二步：設定回呼網址 <a class="header-anchor" href="#第二步-設定回呼網址" aria-label="Permalink to &quot;第二步：設定回呼網址&quot;">​</a></h3><p>在 Dropbox App 詳情頁找到 OAuth 或 Redirect URI 設定，加入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://你的網域/api/oauth/dropbox/callback</span></span></code></pre></div><p>如果你平常會從多個網域開後台，請把對應的回呼網址都加上。</p><p><img src="'+a+'" alt="設定回呼網址" loading="lazy"></p><h3 id="第三步-設定權限-scopes" tabindex="-1">第三步：設定權限 Scopes <a class="header-anchor" href="#第三步-設定權限-scopes" aria-label="Permalink to &quot;第三步：設定權限 Scopes&quot;">​</a></h3><p>進入 <code>Permissions</code> 分頁，至少勾選：</p><table tabindex="0"><thead><tr><th>權限</th><th>是否必要</th><th>用途</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>必要</td><td>查詢帳號基本資訊和容量</td></tr><tr><td><code>files.metadata.read</code></td><td>必要</td><td>讀取檔案 / 目錄 metadata</td></tr><tr><td><code>files.metadata.write</code></td><td>必要</td><td>建立目錄等 metadata 寫入</td></tr><tr><td><code>files.content.write</code></td><td>必要</td><td>上傳檔案，缺少會出現 <code>required scope &#39;files.content.write&#39;</code></td></tr><tr><td><code>files.content.read</code></td><td>建議</td><td>下載、預覽、暫時連結等讀取能力</td></tr></tbody></table><p>勾選後，請記得按頁面底部的 <code>Submit</code>。</p><p><img src="'+d+'" alt="新增權限" loading="lazy"></p><p>如果你後來修改了 Scopes，必須重新跑一次「取得 Token」流程。舊的 Refresh Token 不會自動取得新權限。</p><h3 id="第四步-記下-app-資訊" tabindex="-1">第四步：記下 App 資訊 <a class="header-anchor" href="#第四步-記下-app-資訊" aria-label="Permalink to &quot;第四步：記下 App 資訊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dropbox 後台欄位</th><th>ImgBed 欄位</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="第五步-回-imgbed-填寫-dropbox-渠道" tabindex="-1">第五步：回 ImgBed 填寫 Dropbox 渠道 <a class="header-anchor" href="#第五步-回-imgbed-填寫-dropbox-渠道" aria-label="Permalink to &quot;第五步：回 ImgBed 填寫 Dropbox 渠道&quot;">​</a></h3><table tabindex="0"><thead><tr><th>頁面欄位</th><th>填寫內容</th></tr></thead><tbody><tr><td>渠道名稱</td><td>自己取，例如 <code>Dropbox主帳號</code></td></tr><tr><td>App Key</td><td>Dropbox App 的 <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox App 的 <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>先留空，下一步取得</td></tr><tr><td>根目錄</td><td>選填，預設 <code>imgbed</code></td></tr><tr><td>備註</td><td>選填</td></tr></tbody></table><p><img src="'+o+'" alt="取得 Token" loading="lazy"></p><h3 id="第六步-取得-refresh-token" tabindex="-1">第六步：取得 Refresh Token <a class="header-anchor" href="#第六步-取得-refresh-token" aria-label="Permalink to &quot;第六步：取得 Refresh Token&quot;">​</a></h3><ol><li>在 ImgBed 點「取得 Token」。</li><li>登入要綁定的 Dropbox 帳號。</li><li>依提示授權。</li><li>成功後，回呼頁會顯示 <code>Refresh Token</code>。</li><li>複製它。</li><li>回到 ImgBed，貼到 <code>Refresh Token</code> 欄位。</li></ol><p><img src="'+p+'" alt="複製 Token" loading="lazy"></p><h2 id="新增完成後怎麼檢查" tabindex="-1">新增完成後怎麼檢查 <a class="header-anchor" href="#新增完成後怎麼檢查" aria-label="Permalink to &quot;新增完成後怎麼檢查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>檢查項目</th><th>檢查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出現</td><td>儲存後頁面看得到 Dropbox 渠道</td></tr><tr><td>渠道是否能啟用</td><td>開關可以正常打開</td></tr><tr><td>Token 是否已儲存</td><td>詳情頁看得到 Refresh Token 已保存</td></tr><tr><td>上傳是否正常</td><td>上傳測試圖後，Dropbox App 目錄出現檔案</td></tr></tbody></table><p>如果開啟容量限制，可以點查詢額度。成功後卡片會顯示已用容量、總容量和更新時間。</p><p><img src="'+r+`" alt="查詢額度成功" loading="lazy"></p><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><table tabindex="0"><thead><tr><th>問題</th><th>處理方式</th></tr></thead><tbody><tr><td>系統提示設定不完整</td><td>檢查 <code>App Key</code>、<code>App Secret</code>、<code>Refresh Token</code> 是否都填了</td></tr><tr><td>授權成功但沒有 Refresh Token</td><td>重新點「取得 Token」，確認走的是離線授權</td></tr><tr><td>上傳出現 <code>required scope &#39;files.content.write&#39;</code></td><td>回 Dropbox 勾選 <code>files.content.write</code>，按 <code>Submit</code> 後重新取得 Refresh Token</td></tr><tr><td>回呼失敗</td><td>確認回呼網址是 <code>https://你的網域/api/oauth/dropbox/callback</code></td></tr><tr><td>找不到檔案</td><td>確認 App 是用 <code>App folder</code> 模式建立</td></tr></tbody></table><h2 id="快速流程" tabindex="-1">快速流程 <a class="header-anchor" href="#快速流程" aria-label="Permalink to &quot;快速流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打開 Dropbox App Console</span></span>
<span class="line"><span>-&gt; 建立 App</span></span>
<span class="line"><span>-&gt; 存取類型選 App folder</span></span>
<span class="line"><span>-&gt; 設定回呼 https://你的網域/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Permissions 勾選必要 scopes</span></span>
<span class="line"><span>-&gt; 按 Submit</span></span>
<span class="line"><span>-&gt; 複製 App Key 和 App Secret</span></span>
<span class="line"><span>-&gt; 回 ImgBed 填寫</span></span>
<span class="line"><span>-&gt; 點取得 Token</span></span>
<span class="line"><span>-&gt; 複製回呼頁的 Refresh Token</span></span>
<span class="line"><span>-&gt; 貼回 ImgBed 儲存</span></span></code></pre></div>`,39)])])}const y=s(c,[["render",h]]);export{A as __pageData,y as default};
